Set remembered password history to conform to site policy.   Run the following script to add or modify the `pam_pwhistory.so` and `pam_unix.so` lines to include the `remember` option:  ``` #!/usr/bin/env bash  {  file="/etc/authselect/$(head -1 /etc/authselect/authselect.conf | grep 'custom/')/system-auth"  if ! grep -Pq -- '^\h*password\h+(requisite|required|sufficient)\h+pam_pwhistory\.so\h+([^#
]+\h+)?remember=([5-9]|[1-9][0-9]+) .*$' "$file"; then  if grep -Pq -- '^\h*password\h+(requisite|required|sufficient)\h+pam_pwhistory\.so\h+([^#
]+\h+)?remember=\d+ .*$' "$file"; then  sed -ri 's/^\s*(password\s+(requisite|required|sufficient)\s+pam_pwhistory\.so\s+([^#
]+\s+)?)(remember=\S+\s*)(\s+.*)?$/\1 remember=5 \5/' $file  elif grep -Pq -- '^\h*password\h+(requisite|required|sufficient)\h+pam_pwhistory\.so\h+([^#
]+\h+)?.*$' "$file"; then  sed -ri '/^\s*password\s+(requisite|required|sufficient)\s+pam_pwhistory\.so/ s/$/ remember=5/' $file  else  sed -ri '/^\s*password\s+(requisite|required|sufficient)\s+pam_unix\.so/i password required pam_pwhistory.so remember=5 use_authtok' $file  fi  fi  if ! grep -Pq -- '^\h*password\h+(requisite|required|sufficient)\h+pam_unix\.so\h+([^#
]+\h+)?remember=([5-9]|[1-9][0-9]+) .*$' "$file"; then  if grep -Pq -- '^\h*password\h+(requisite|required|sufficient)\h+pam_unix\.so\h+([^#
]+\h+)?remember=\d+ .*$' "$file"; then  sed -ri 's/^\s*(password\s+(requisite|required|sufficient)\s+pam_unix\.so\s+([^#
]+\s+)?)(remember=\S+\s*)(\s+.*)?$/\1 remember=5 \5/' $file  else  sed -ri '/^\s*password\s+(requisite|required|sufficient)\s+pam_unix\.so/ s/$/ remember=5/' $file  fi  fi  authselect apply-changes } ```
